module simple_pwm #(
    parameter integer COUNTER_WIDTH = 8
) (
    input  logic                     clk,
    input  logic                     rst_n,
    input  logic                     enable,
    input  logic [COUNTER_WIDTH-1:0] duty_cycle,
    input  logic [COUNTER_WIDTH-1:0] period,
    output logic                     pwm_out
);

    // FM state variable owner: free-running PWM counter.
    logic [COUNTER_WIDTH-1:0] counter;

    // Explicit next-state datapath for function_model state_updates.counter_next.
    logic [COUNTER_WIDTH-1:0] counter_plus_one;
    logic [COUNTER_WIDTH-1:0] counter_next;

    // Output rule names are represented as real control signals used by pwm_out logic.
    logic pwm_out_high;
    logic pwm_out_low;
    logic pwm_out_off;

    // Counter increment datapath used by FM1/FM2 side-effect: "counter increments by 1".
    assign counter_plus_one = counter + {{(COUNTER_WIDTH-1){1'b0}}, 1'b1};

    // FM1/FM2 state update expression:
    // counter_next = counter + 1 if (counter + 1) < period else 0.
    // Guard period==0 so modulo-by-zero behavior is deterministic: force 0.
    assign counter_next = (period == {COUNTER_WIDTH{1'b0}}) ? {COUNTER_WIDTH{1'b0}} :
                          ((counter_plus_one < period) ? counter_plus_one : {COUNTER_WIDTH{1'b0}});

    // FM output rules mapped to real compare logic.
    assign pwm_out_high = (counter < duty_cycle);
    assign pwm_out_low  = (counter >= duty_cycle);
    assign pwm_out_off  = 1'b0;

    // Active-low asynchronous reset per SSOT coding rules.
    // enable==0 implements FM3: counter=0 and pwm_out=0.
    // enable==1 accepts FM1/FM2 every cycle and updates both state/output once.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            counter  <= {COUNTER_WIDTH{1'b0}};
            pwm_out  <= 1'b0;
        end else if (enable) begin
            counter  <= counter_next;
            if (pwm_out_high) begin
                pwm_out <= 1'b1;
            end else if (pwm_out_low) begin
                pwm_out <= 1'b0;
            end else begin
                pwm_out <= 1'b0;
            end
        end else begin
            counter  <= {COUNTER_WIDTH{1'b0}};
            pwm_out  <= pwm_out_off;
        end
    end

endmodule

